                  dateNumber[i].style.color = "red"; 
                }

              }

            }  
*/

          }

          handleEventClick = (arg) => { // bind with an arrow function
            //alert(arg.dateStr)
            //console.log(arg)
            this.setState({dateStr: arg.event.startStr})
            this.setState({screen: 2})
          }


          handleDateClick = (arg) => { // bind with an arrow function
            //alert(arg.dateStr)
            //console.log(arg)
            this.setState({dateStr: arg.dateStr})
            this.setState({screen: 2})
          }




          render() {


            var todayDate = "Loading ..."
            var content = []
            var events = []




            if (this.state.screen === 1) {
              todayDate = ""
              for (let x in this.state.results) {
                var inTomorrow = true 
                for (let y in this.state.results[x].data) {
                  if (!this.state.results[x].data[y].inTomorrow) {
                    inTomorrow = false
                  }
                  for (let z in this.state.results[x].data[y].members) {
                    if (!this.state.results[x].data[y].members[z].inTomorrow) {
                      inTomorrow = false
                    }
                  }
                }
                if (!inTomorrow) {
                  events.push({id: "", groupId: this.state.results[x].groupId,title: " - Rotation Change - ",  date: this.state.results[x].eventDate, color: "#FF7F7F", textColor: "black" })
                }
              }


              content.push(                 <FullCalendar
                plugins={[ dayGridPlugin, interactionPlugin ]}
                initialView="dayGridMonth"
                events={events}
                eventClick={this.handleEventClick}
                dateClick={this.handleDateClick}
                eventOrder="id"
                eventDidMount={this.handleDidMount}

              />)



            }


            if (this.state.screen === 2) {
              todayDate = ""
              var dateData = this.state.results.filter(Record => Record.eventDate === this.state.dateStr)
              //console.log(dateData)
              for (let index in dateData) {
                content.push(<div>{dateData[index].formatDate}</div>)
                content.push(<div><hr></hr></div>)
                for (let y in dateData[index].data) {
                  var colorFaculty = "#000000"
                  if (!dateData[index].data[y].inTomorrow) {
                    colorFaculty = "red"
                    inTomorrow = false
                  }

                  content.push(<div style={{color: colorFaculty}}>{dateData[index].data[y].assignment + " - " + dateData[index].data[y].name}</div>)
                  content.push(<div>&nbsp;</div>)

                  for (let z in dateData[index].data[y].members) {
                    var colorRes = "#000000"
                    if (!dateData[index].data[y].members[z].inTomorrow) {
                        colorRes = "red"
                        inTomorrow = false
                    }
                    //events.push({ title: this.state.results[x].data[y].members[z].name, date: this.state.results[x].eventDate, id: 1, color: "#FF7F7F", textColor: "black" })
                    content.push(<div style={{color: colorRes}}>----- {dateData[index].data[y].members[z].name}</div>)
                    content.push(<div>&nbsp;</div>)

                    //overlap
                    var contentWith = "|***| "
                    for (let i in dateData[index].data[y].members[z].overlap) {
                        contentWith += "with (" + dateData[index].data[y].members[z].overlap[i].name + ") " + dateData[index].data[y].members[z].overlap[i].daysTogether + " days |***| "
                    }
                    content.push(<div style={{color: "blue"}}>{contentWith}</div>)
                    content.push(<div>&nbsp;</div>)

                  }
                  content.push(<div>***************************************************************************************************************************</div>)

                }


              }

            }



            /*
