                    content.push(<div>&nbsp;</div>)
                    var event2 = []
                    for (let z in this.state.results[x].data[y].members) {
                        var colorRes = "#CCCCCC"
                        if (!this.state.results[x].data[y].members[z].inTomorrow) {
                            colorRes = "#FF7F7F"
                            inTomorrow = false
                        }
                        //events.push({ title: this.state.results[x].data[y].members[z].name, date: this.state.results[x].eventDate, id: 1, color: "#FF7F7F", textColor: "black" })
                        content.push(<div style={{color: colorRes}}>----- {this.state.results[x].data[y].members[z].name}</div>)
                        content.push(<div>&nbsp;</div>)

                        //overlap
                        var contentWith = "|***| "
                        for (let i in this.state.results[x].data[y].members[z].overlap) {
                            contentWith += "with (" + this.state.results[x].data[y].members[z].overlap[i].name + ") " + this.state.results[x].data[y].members[z].overlap[i].daysTogether + " days |***| "
                        }
                        content.push(<div style={{color: "blue"}}>{contentWith}</div>)
                        content.push(<div>&nbsp;</div>)

                        event2.push({id: this.state.results[x].data[y].members[z].id, groupId: this.state.results[x].groupId,title: "           " + this.state.results[x].data[y].members[z].name,  date: this.state.results[x].eventDate, color: colorRes, textColor: "black" })

                    }

                    if (this.state.teamValue === "" || this.state.teamValue === this.state.results[x].data[y].assignment.replace("M-L Wards Team ", "")) {
                      events.push({id: this.state.results[x].data[y].id, groupId: this.state.results[x].groupId,title: "",  date: this.state.results[x].eventDate, color: "#CCCCCC"})
